import React, { useEffect, useState } from 'react';
import api from '../api';

const AppointmentList = () => {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [doctors, setDoctors] = useState<any[]>([]);
  
  const [selectedPat, setSelectedPat] = useState('');
  const [selectedDoc, setSelectedDoc] = useState('');
  const [appDate, setAppDate] = useState('');

  const fetchData = async () => {
    const [resApp, resPat, resDoc] = await Promise.all([
      api.get('appointments/'), api.get('patients/'), api.get('doctors/')
    ]);
    setAppointments(resApp.data);
    setPatients(resPat.data);
    setDoctors(resDoc.data);
  };

  useEffect(() => { fetchData(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('appointments/', {
        patient: selectedPat, // ID sa Patient (Required)
        doctor: selectedDoc,   // ID sa Doctor (Required)
        appointment_date: appDate,
        status: 'Pending'
      });
      fetchData();
    } catch (err: any) { console.error(err.response?.data); }
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="grid grid-cols-1 md:grid-cols-4 gap-2 bg-gray-50 p-4 rounded-lg">
        <select className="border p-2 rounded" value={selectedPat} onChange={e => setSelectedPat(e.target.value)} required>
          <option value="">Select Patient</option>
          {patients.map(p => <option key={p.patient_id} value={p.patient_id}>{p.first_name} {p.last_name}</option>)}
        </select>
        <select className="border p-2 rounded" value={selectedDoc} onChange={e => setSelectedDoc(e.target.value)} required>
          <option value="">Select Doctor</option>
          {doctors.map(d => <option key={d.doctor_id} value={d.doctor_id}>Dr. {d.last_name}</option>)}
        </select>
        <input type="datetime-local" className="border p-2 rounded" value={appDate} onChange={e => setAppDate(e.target.value)} required />
        <button type="submit" className="bg-indigo-600 text-white rounded p-2">Schedule</button>
      </form>
      {/* Table for appointments here... */}
    </div>
  );
};

export default AppointmentList;
